// Home Screen
const HomeScreen = () => {
  const navigation = useNavigation();

  useDeepLinkHandler();

  const deepLinkExamples = [
    { label: 'Profile #123', url: 'myapp://profile/123' },
    { label: 'Profile #456 (with tab)', url: 'myapp://profile/456?tab=posts' },
    { label: 'Payment Confirm', url: 'myapp://payment/confirm?txn=TXN001&amount=49.99' },
    { label: 'Payment History', url: 'myapp://payment/history?filter=recent' },
    { label: 'Settings', url: 'myapp://settings?section=notifications' },
    { label: 'Campaign Promo', url: 'myapp://campaign/SUMMER2024?discount=20&source=push' },
    { label: 'Unknown Route', url: 'myapp://unknown/path' },
  ];

  return (
    <View style={styles.container}>
      <Text style={styles.title}>🏠 Home Screen</Text>
      <Text style={styles.subtitle}>Deep Link Handler Demo</Text>
      <Text style={styles.description}>
        Tap buttons below to simulate deep links from marketing campaigns and push notifications.
      </Text>

      <View style={styles.linkContainer}>
        {deepLinkExamples.map((example, index) => (
          <TouchableOpacity
            key={index}
            style={styles.linkButton}
            onPress={() => handleDeepLinkNavigation(example.url, navigation)}
          >
            <Text style={styles.linkButtonText}>{example.label}</Text>
            <Text style={styles.linkUrl}>{example.url}</Text>
          </TouchableOpacity>
        ))}
      </View>

      <TouchableOpacity
        style={[styles.linkButton, styles.simulateButton]}
        onPress={() => simulateDeepLink('myapp://profile/999')}
      >
        <Text style={[styles.linkButtonText, { color: '#fff' }]}>
          🔗 Simulate via Linking.openURL
        </Text>
      </TouchableOpacity>
    </View>
  );
};

