// ==================== MAIN APP ====================

const App = () => {
  // Global deep link listener for analytics/logging
  useEffect(() => {
    const handleDeepLink = (event) => {
      const parsed = parseDeepLink(event.url);
      if (parsed) {
        console.log('Analytics: Deep link opened', {
          route: parsed.route,
          params: parsed.queryParams,
          timestamp: new Date().toISOString(),
        });
      }
    };

    const subscription = Linking.addEventListener('url', handleDeepLink);

    // Check for initial URL on cold start
    Linking.getInitialURL().then((url) => {
      if (url) {
        console.log('App opened via deep link:', url);
      }
    });

    return () => {
      subscription.remove();
    };
  }, []);

  return (
    <NavigationContainer
      linking={linking}
      fallback={
        <View style={styles.loadingContainer}>
          <Text style={styles.loadingText}>Loading...</Text>
        </View>
      }
      onStateChange={(state) => {
        const currentRoute = state?.routes[state.index];
        if (currentRoute) {
          console.log('Navigation state changed:', {
            screen: currentRoute.name,
            params: currentRoute.params,
          });
        }
      }}
    >
      <Stack.Navigator
        initialRouteName="Home"
        screenOptions={{
          headerStyle: { backgroundColor: '#2c3e50' },
          headerTintColor: '#fff',
          headerTitleStyle: { fontWeight: 'bold' },
        }}
      >
        <Stack.Screen
          name="Home"
          component={HomeScreen}
          options={{ title: 'Deep Link Demo' }}
        />
        <Stack.Screen
          name="Profile"
          component={ProfileScreen}
          options={({ route }) => ({
            title: `Profile #${route.params?.userId || ''}`,
          })}
        />
        <Stack.Screen
          name="PaymentConfirm"
          component={PaymentConfirmScreen}
          options={{ title: 'Confirm Payment' }}
        />
        <Stack.Screen
          name="PaymentHistory"
          component={PaymentHistoryScreen}
          options={{ title: 'Payment History' }}
        />
        <Stack.Screen
          name="Settings"
          component={SettingsScreen}
          options={{ title: 'Settings' }}
        />
        <Stack.Screen
          name="Campaign"
          component={CampaignScreen}
          options={({ route }) => ({
            title: `Campaign ${route.params?.campaignId || ''}`,
          })}
        />
        <Stack.Screen
          name="NotFound"
          component={NotFoundScreen}
          options={{ title: 'Not Found' }}
        />
      </Stack.Navigator>
    </NavigationContainer>
  );
};

